import React, { useEffect, useState } from 'react';
import { slaService } from '../api/dashboardServices';
import '../styles/ecoflow-3d-theme.css';

function SLAMonitoring() {
  const [loading, setLoading] = useState(true);
  const [policies, setPolicies] = useState([]);
  const [escalations, setEscalations] = useState([]);
  const [metrics, setMetrics] = useState(null);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const [policiesData, escalationsData, metricsData] = await Promise.all([
        slaService.getPolicies(),
        slaService.getEscalations(),
        slaService.getMetrics()
      ]);
      setPolicies(policiesData);
      setEscalations(escalationsData);
      setMetrics(metricsData);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const getEscalationLevel = (minutesOld, escalationMinutes) => {
    const level = Math.floor(minutesOld / escalationMinutes);
    return Math.min(level, 3);
  };

  const getSeverityColor = (severity) => {
    switch (severity) {
      case 'critical': return '#ff2244';
      case 'high': return '#ff4444';
      case 'medium': return '#ffd93d';
      case 'low': return '#38ef7d';
      default: return '#a0b0c0';
    }
  };

  return (
    <div className="page-header">
      <div>
        <h1 className="page-title">⏱️ SLA Monitoring Dashboard</h1>
        <p className="page-subtitle">Track service level agreements and escalation status</p>
      </div>

      <div className="page-content">
        {loading ? (
          <div className="spinner" style={{ margin: '40px auto' }}></div>
        ) : (
          <>
            {/* SLA Metrics */}
            {metrics && (
              <div className="grid grid-4">
                <div className="card">
                  <div className="card-header">
                    <div className="card-subtitle">Overall Compliance</div>
                  </div>
                  <div style={{ fontSize: '36px', fontWeight: '700', marginTop: '8px', color: '#38ef7d' }}>
                    {metrics.overallCompliance}%
                  </div>
                  <div className="badge badge-success" style={{ marginTop: '8px' }}>✓ On Track</div>
                </div>

                <div className="card">
                  <div className="card-header">
                    <div className="card-subtitle">Active Incidents</div>
                  </div>
                  <div style={{ fontSize: '36px', fontWeight: '700', marginTop: '8px' }}>
                    {metrics.activeIncidents}
                  </div>
                  <div className="badge badge-info" style={{ marginTop: '8px' }}>Current</div>
                </div>

                <div className="card">
                  <div className="card-header">
                    <div className="card-subtitle">Breached Today</div>
                  </div>
                  <div style={{ fontSize: '36px', fontWeight: '700', marginTop: '8px', color: '#ff4444' }}>
                    {metrics.breachedToday}
                  </div>
                  <div className="badge badge-error" style={{ marginTop: '8px' }}>Critical</div>
                </div>

                <div className="card">
                  <div className="card-header">
                    <div className="card-subtitle">At Risk (Next 1h)</div>
                  </div>
                  <div style={{ fontSize: '36px', fontWeight: '700', marginTop: '8px', color: '#ffd93d' }}>
                    {metrics.atRisk}
                  </div>
                  <div className="badge badge-warning" style={{ marginTop: '8px' }}>Warning</div>
                </div>
              </div>
            )}

            {/* Escalations */}
            <div style={{ marginTop: '32px' }}>
              <div className="card">
                <div className="card-header">
                  <div className="card-title">🚨 Pending Escalations</div>
                  {escalations.length > 0 && <div className="badge badge-critical">{escalations.length}</div>}
                </div>

                {escalations.length === 0 ? (
                  <div style={{ padding: '32px', textAlign: 'center', color: '#a0b0c0' }}>
                    ✓ No escalations pending
                  </div>
                ) : (
                  <div className="table-container">
                    <table className="table">
                      <thead>
                        <tr>
                          <th>Incident</th>
                          <th>Severity</th>
                          <th>Age</th>
                          <th>SLA Target</th>
                          <th>Status</th>
                          <th>Action</th>
                        </tr>
                      </thead>
                      <tbody>
                        {escalations.map((esc, idx) => {
                          const level = getEscalationLevel(esc.age_minutes, esc.escalation_minutes);
                          return (
                            <tr key={idx} className="critical">
                              <td style={{ fontWeight: '600' }}>#{esc.incident_id}</td>
                              <td>
                                <span className="badge" style={{ background: `${getSeverityColor(esc.severity)}40`, color: getSeverityColor(esc.severity), border: `1px solid ${getSeverityColor(esc.severity)}60` }}>
                                  {esc.severity.toUpperCase()}
                                </span>
                              </td>
                              <td>{esc.age_minutes} min</td>
                              <td>{esc.target_minutes} min</td>
                              <td>
                                <span className="badge badge-critical">
                                  {'🔴 ESCALATED'}
                                </span>
                              </td>
                              <td>
                                <button className="btn btn-danger btn-sm">📞 Escalate</button>
                              </td>
                            </tr>
                          );
                        })}
                      </tbody>
                    </table>
                  </div>
                )}
              </div>
            </div>

            {/* SLA Policies */}
            <div style={{ marginTime: '32px', marginTop: '32px' }}>
              <div className="card">
                <div className="card-header">
                  <div className="card-title">SLA Policies</div>
                </div>
                <div className="grid grid-2">
                  {policies.map((policy, idx) => (
                    <div key={idx} style={{ padding: '16px', background: 'rgba(0, 0, 0, 0.2)', borderRadius: '8px', border: policy.is_active ? '1px solid rgba(0, 255, 136, 0.3)' : '1px solid rgba(160, 176, 192, 0.2)' }}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start' }}>
                        <div>
                          <div style={{ fontSize: '13px', fontWeight: '600', color: '#d0d8e8' }}>
                            {policy.zone_name}
                          </div>
                          <div style={{ fontSize: '12px', color: '#a0b0c0', marginTop: '4px' }}>
                            {policy.severity.toUpperCase()} Severity
                          </div>
                        </div>
                        {policy.is_active && <div className="badge badge-success">Active</div>}
                      </div>
                      <div style={{ marginTop: '12px', display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px' }}>
                        <div>
                          <div style={{ fontSize: '11px', color: '#a0b0c0' }}>Target</div>
                          <div style={{ fontSize: '16px', fontWeight: '600', marginTop: '4px' }}>
                            {policy.target_minutes}m
                          </div>
                        </div>
                        <div>
                          <div style={{ fontSize: '11px', color: '#a0b0c0' }}>Escalation</div>
                          <div style={{ fontSize: '16px', fontWeight: '600', marginTop: '4px', color: '#ffd93d' }}>
                            {policy.escalation_minutes}m
                          </div>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

export default SLAMonitoring;
